CREATE PROCEDURE [ipc].[csp_measurement_detail_status_change]
@MeasurementId UNIQUEIDENTIFIER,
@user_cd nvarchar(100)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @average_value float;
    DECLARE @range_value float;
	DECLARE @plant_cd nvarchar(50);
	DECLARE @lot_id uniqueidentifier;
	DECLARE @test_cd nvarchar(50);
	DECLARE @cl_mean float;
	DECLARE @cl_usigma float;
	DECLARE @cl_lsigma float;
	DECLARE @result NVARCHAR(100);
	DECLARE @precision int;
	DECLARE @lcl_actual float;
	DECLARE @ucl_actual float;
	DECLARE @row_count int;

	SELECT @plant_cd = plant_cd, @lot_id = lot_id, @test_cd = test_cd FROM ipc.measurement WHERE id = @MeasurementId;


    -- Calculate average and range from active measurement details
    WITH ActiveDetails AS (
        SELECT value 
        FROM ipc.measurement_detail 
        WHERE measurement_id = @MeasurementId 
        AND measurement_detail_status = 'Active'
    )
    SELECT 
        @average_value = AVG(CAST(value AS DECIMAL(18, 6))),
        @range_value = MAX(CAST(value AS DECIMAL(18, 6))) - MIN(CAST(value AS DECIMAL(18, 6))),
		@row_count = COUNT(*)
    FROM ActiveDetails;

	SELECT @precision = precision FROM ipc.test (NOLOCK) WHERE test_cd = @test_cd 
	IF @@rowcount = 0
	BEGIN
		SET @result = 'ERROR: Test not Found'
	END

	SELECT 
	@cl_mean = cl_mean, @cl_lsigma = cl_lsigma,  @cl_usigma = cl_usigma
	FROM ipc.specification_lot (NOLOCK) 
	WHERE plant_cd = @plant_cd and test_cd = @test_cd and lot_id = @lot_id
	IF @@rowcount = 0
	BEGIN
		SET @result = 'WARNING: No Lot specification found'
	END


	SET @lcl_actual = round(@cl_mean - (3* @cl_lsigma/SQRT(@row_count)),@precision)
	SET @ucl_actual = round(@cl_mean + (3* @cl_usigma/SQRT(@row_count)),@precision)

	 -- Update the measurement with calculated values
    UPDATE ipc.measurement 
    SET 
        avg_value = @average_value,
        range = @range_value,
        last_edit_date = GETUTCDATE(),
		lcl_actual = @lcl_actual,
		ucl_actual = @ucl_actual,
		last_edit_user_cd = @user_cd
    WHERE id = @MeasurementId;
END;

