CREATE PROCEDURE [ipc].[csp_spec_condition_get_affected_pro]
     @specification_set_condition_id uniqueidentifier
	
   
AS

DECLARE @log_action nvarchar(500)
DECLARE @log_starttime datetime
DECLARE @result		NVARCHAR(100)


-- Declare variables for all columns
DECLARE @id UNIQUEIDENTIFIER;
DECLARE @plant_cd NVARCHAR(50);
DECLARE @priority INT;
DECLARE @specification_set_cd NVARCHAR(50);
DECLARE @test_mode_cd NVARCHAR(50);
DECLARE @test_type_cd NVARCHAR(50);
DECLARE @test_cd NVARCHAR(50);
DECLARE @customer_cd NVARCHAR(50);
DECLARE @customer_cd_st NVARCHAR(50);
DECLARE @customer_product_cd NVARCHAR(50);
DECLARE @material_id UNIQUEIDENTIFIER;
DECLARE @psn_cd NVARCHAR(50);
DECLARE @product_type_cd NVARCHAR(50);
DECLARE @size_design_cd NVARCHAR(50);
DECLARE @pin_design_cd NVARCHAR(50);
DECLARE @body_color_cd NVARCHAR(50);
DECLARE @cap_color_cd NVARCHAR(50);
DECLARE @polymer_cd NVARCHAR(50);
DECLARE @lod_cd NVARCHAR(50);
DECLARE @pin_treatment_cd NVARCHAR(50);
DECLARE @surface_treatment_cd NVARCHAR(50);
DECLARE @weight_spec_cd NVARCHAR(50);
DECLARE @manufacturing_type_cd NVARCHAR(50);
DECLARE @equipment_model NVARCHAR(50);
DECLARE @material_group_cd NVARCHAR(50);
DECLARE @product_family_cd NVARCHAR(50);
DECLARE @is_printed BIT;
DECLARE @is_active BIT;
DECLARE @created_date DATETIMEOFFSET(7);
DECLARE @last_edit_date DATETIMEOFFSET(7);
DECLARE @last_edit_user_cd NVARCHAR(50);

-- Select data into variables
SELECT 
    @id = id,    @plant_cd = plant_cd,    @priority = priority,    @specification_set_cd = specification_set_cd,    @test_mode_cd = test_mode_cd,    @test_type_cd = test_type_cd,
    @test_cd = test_cd,    @customer_cd = customer_cd,    @customer_cd_st = customer_cd_st,    @customer_product_cd = customer_product_cd,    @material_id = material_id,
    @psn_cd = psn_cd,    @product_type_cd = product_type_cd,    @size_design_cd = size_design_cd,    @pin_design_cd = pin_design_cd,    @body_color_cd = body_color_cd,
    @cap_color_cd = cap_color_cd,    @polymer_cd = polymer_cd,    @lod_cd = lod_cd,    @pin_treatment_cd = pin_treatment_cd,    @surface_treatment_cd = surface_treatment_cd,
    @weight_spec_cd = weight_spec_cd,    @manufacturing_type_cd = manufacturing_type_cd,    @equipment_model = equipment_model,    @material_group_cd = material_group_cd,
    @product_family_cd = product_family_cd,    @is_printed = is_printed,    @is_active = is_active,   
	@created_date = created_date,    @last_edit_date = last_edit_date,    @last_edit_user_cd = last_edit_user_cd
FROM [ipc].[specification_set_condition]
WHERE id = @specification_set_condition_id
--and is_active = 1  ------------------------------TO ADD AGAIN!!!!!

DECLARE @conditions TABLE (test_cd NVARCHAR(50), existing_spec_cd NVARCHAR(50), new_spec_cd NVARCHAR(50), existing_priority int, new_priority int,
							lot_nr NVARCHAR(50),process_order_nr NVARCHAR(50)	  ,process_order_step_status_cd NVARCHAR(50)      ,customer_cd NVARCHAR(50)
						 ,customer_st_cd NVARCHAR(50)      ,customer_product_cd NVARCHAR(50)      ,material_id UNIQUEIDENTIFIER      ,psn_cd NVARCHAR(50)
						,size_design_cd NVARCHAR(50)      ,pin_design_cd NVARCHAR(50)      ,body_color_cd NVARCHAR(50)      ,cap_color_cd NVARCHAR(50)
      ,polymer_cd NVARCHAR(50)      ,lod_cd NVARCHAR(50)      ,pin_treatment_cd NVARCHAR(50)      ,surface_treatment_cd NVARCHAR(50)      ,weight_spec_cd NVARCHAR(50)
      ,manufacturing_type_cd NVARCHAR(50)      ,equipment_model_cd NVARCHAR(50)      ,material_group_cd NVARCHAR(50)      ,product_family_cd NVARCHAR(50)      ,is_printed bit)

INSERT INTO @conditions
SELECT 	sl.test_cd 
		, sl.specification_set_cd 'Existing Spec Cd'
	   ,@specification_set_cd 'New Spec Cd'
	   ,sc.priority 'Existing Priority'
	   ,@priority 'New Priority'
      ,[LotNr]
      ,[ProcessOrderNr]
	  ,[ProcessOrderStepStatusCd]
      ,[CustomerCd]
      ,[CustomerStCd]
      ,[CustomerProductCd]
      ,[MaterialId]
      ,[PsnCd]
      ,[SizeDesignCd]
      ,[PinDesignCd]
      ,[BodyColorCd]
      ,[CapColorCd]
      ,[PolymerCd]
      ,[LODCd]
      ,[PinTreatmentCd]
      ,[SurfaceTreatmentCd]
      ,[WeightSpecCd]
      ,[ManufacturingTypeCd]
      ,[EquipmentModelCd]
      ,[MaterialGroupCd]
      ,[ProductFamilyCd]
      ,[IsPrinted]
	  
FROM [sub].[vw_process_order_data_to_link_condition] v
JOIN ipc.specification_lot sl on sl.lot_id = v.lotid
JOIN ipc.specification_set_condition sc on sl.specification_set_condition_id = sc.id
WHERE (@plant_cd IS NULL OR PlantCd = @plant_cd)
  AND (@customer_cd IS NULL OR CustomerCd = @customer_cd)
  AND (@customer_cd_st IS NULL OR CustomerStCd = @customer_cd_st)
  AND (@customer_product_cd IS NULL OR CustomerProductCd = @customer_product_cd)
  AND (@material_id IS NULL OR MaterialId = @material_id)
  AND (@psn_cd IS NULL OR PsnCd = @psn_cd)
  AND (@size_design_cd IS NULL OR SizeDesignCd = @size_design_cd)
  AND (@pin_design_cd IS NULL OR PinDesignCd = @pin_design_cd)
  AND (@body_color_cd IS NULL OR BodyColorCd = @body_color_cd)
  AND (@cap_color_cd IS NULL OR CapColorCd = @cap_color_cd)
  AND (@polymer_cd IS NULL OR PolymerCd = @polymer_cd)
  AND (@lod_cd IS NULL OR LODCd = @lod_cd)
  AND (@pin_treatment_cd IS NULL OR PinTreatmentCd = @pin_treatment_cd)
  AND (@surface_treatment_cd IS NULL OR SurfaceTreatmentCd = @surface_treatment_cd)
  AND (@weight_spec_cd IS NULL OR WeightSpecCd = @weight_spec_cd)
  AND (@manufacturing_type_cd IS NULL OR ManufacturingTypeCd = @manufacturing_type_cd)
  AND (@equipment_model IS NULL OR EquipmentModelCd = @equipment_model)
  AND (@material_group_cd IS NULL OR MaterialGroupCd = @material_group_cd)
  AND (@product_family_cd IS NULL OR ProductFamilyCd = @product_family_cd)
  AND (@is_printed IS NULL OR IsPrinted = @is_printed)
  AND ProcessOrderStepStatusCd in ('Running', 'Released')
  AND sl.specification_set_cd <> @specification_set_cd
  and (		(@priority > sc.priority) 
		OR	(	(@priority = sc.priority) and  (@last_edit_date > sc.last_edit_date) )
	  )

SELECT 
    @id AS id,
    @plant_cd AS plant_cd,
    @priority AS priority,
    @specification_set_cd AS specification_set_cd,
    @test_mode_cd AS test_mode_cd,
    @test_type_cd AS test_type_cd,
    @test_cd AS test_cd,
    @customer_cd AS customer_cd,
    @customer_cd_st AS customer_cd_st,
    @customer_product_cd AS customer_product_cd,
    @material_id AS material_id,
    @psn_cd AS psn_cd,
    @product_type_cd AS product_type_cd,
    @size_design_cd AS size_design_cd,
    @pin_design_cd AS pin_design_cd,
    @body_color_cd AS body_color_cd,
    @cap_color_cd AS cap_color_cd,
    @polymer_cd AS polymer_cd,
    @lod_cd AS lod_cd,
    @pin_treatment_cd AS pin_treatment_cd,
    @surface_treatment_cd AS surface_treatment_cd,
    @weight_spec_cd AS weight_spec_cd,
    @manufacturing_type_cd AS manufacturing_type_cd,
    @equipment_model AS equipment_model,
    @material_group_cd AS material_group_cd,
    @product_family_cd AS product_family_cd,
    @is_printed AS is_printed,
    @is_active AS is_active,
    @created_date AS created_date,
    @last_edit_date AS last_edit_date,
    @last_edit_user_cd AS last_edit_user_cd
FROM [ipc].[specification_set_condition]
WHERE id = @specification_set_condition_id




SELECT 
    process_order_nr,
    process_order_step_status_cd,
    existing_spec_cd ,
	existing_priority,
    new_spec_cd,
    new_priority,
    lot_nr,
    customer_cd,
    customer_st_cd,
    customer_product_cd,
	string_agg(test_cd, ', ') 'List of Tests'
   
FROM @conditions
GROUP BY existing_spec_cd,
    new_spec_cd,
    existing_priority,
    new_priority,
    lot_nr,
    process_order_nr,
    process_order_step_status_cd,
    customer_cd,
    customer_st_cd,
    customer_product_cd

CREATE PROCEDURE [ipc].[Ensure_IoT_DailyPartitions]
(
    @FromDate date,  -- inclusive
    @ToDate   date   -- inclusive
)
AS
BEGIN
    SET NOCOUNT ON;

    IF @ToDate < @FromDate
    BEGIN
        DECLARE @tmp date;
        SET @tmp = @FromDate;
        SET @FromDate = @ToDate;
        SET @ToDate   = @tmp;
    END;

    DECLARE @d date;
    SET @d = @FromDate;

    WHILE @d <= @ToDate
    BEGIN
        IF NOT EXISTS
        (
            SELECT 1
            FROM sys.partition_range_values rv
            JOIN sys.partition_functions pf ON pf.function_id = rv.function_id
            WHERE pf.name = N'PF_IoTByDay'
              AND TRY_CONVERT(date, CONVERT(varchar(10), rv.value, 120)) = @d
        )
        BEGIN
            ALTER PARTITION SCHEME PS_IoTByDay NEXT USED [PRIMARY];
            ALTER PARTITION FUNCTION PF_IoTByDay() SPLIT RANGE (@d);
        END;

        SET @d = DATEADD(day, 1, @d);
    END;
END;

CREATE PROCEDURE [ipc].[IoT_Maintain_SlidingWindow]
(
    @RetentionDays int = 365,
    @PrecreateDays int = 7,
    @Verbose       bit = 1
)
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE @utcToday  date;
    DECLARE @DropDate  date;
    DECLARE @PartNo    int;
    DECLARE @From date;
    DECLARE @To   date;

    SET @utcToday = CAST(SYSUTCDATETIME() AS date);
    SET @DropDate = DATEADD(day, -@RetentionDays, @utcToday);
    SET @PartNo   = $PARTITION.PF_IoTByDay(@DropDate);

    SET @From = DATEADD(day, -@RetentionDays - 7, @utcToday);
    SET @To   = DATEADD(day,  @PrecreateDays,    @utcToday);
    EXEC ipc.Ensure_IoT_DailyPartitions @FromDate = @From, @ToDate = @To;

    IF @Verbose = 1
        PRINT CONCAT('UTC Today=', @utcToday, ' | DropDate=', @DropDate, ' | Partition#=', @PartNo);

    BEGIN TRY
        ALTER TABLE ipc.iot_measurement
        SWITCH PARTITION @PartNo
        TO ipc.iot_measurements_staging;

        IF @Verbose = 1 PRINT 'SWITCH OUT succeeded.';
    END TRY
    BEGIN CATCH
        IF @Verbose = 1 PRINT CONCAT('SWITCH OUT failed: ', ERROR_MESSAGE());
        RETURN;
    END CATCH;

    TRUNCATE TABLE ipc.iot_measurement_staging;
    IF @Verbose = 1 PRINT 'TRUNCATE staging succeeded.';

    BEGIN TRY
        ALTER PARTITION FUNCTION PF_IoTByDay() MERGE RANGE (@DropDate);
        IF @Verbose = 1 PRINT CONCAT('Merged boundary at ', CONVERT(varchar(10), @DropDate, 120), '.');
    END TRY
    BEGIN CATCH
        IF @Verbose = 1 PRINT CONCAT('MERGE failed: ', ERROR_MESSAGE(), ' (will retry next run).');
    END CATCH;
END;

