CREATE PROCEDURE [mas].[csp_audittrail_tablerecord_to_json]
    @table_schema NVARCHAR(50),
    @table_name NVARCHAR(50),
    @table_id UNIQUEIDENTIFIER,
    @json_output NVARCHAR(MAX) OUTPUT
AS
BEGIN
    DECLARE @SQL NVARCHAR(MAX)


    SET @SQL = 'SELECT @JSONOutput = (SELECT * FROM ' + QUOTENAME(@table_schema) + '.' + QUOTENAME(@table_name) + 
               ' WHERE ID = @ID FOR JSON PATH, WITHOUT_ARRAY_WRAPPER)'
	BEGIN TRY
		EXEC sp_executesql @SQL, 
						   N'@ID UNIQUEIDENTIFIER, @JSONOutput NVARCHAR(MAX) OUTPUT', 
						   @ID = @table_id, 
						   @JSONOutput = @json_output OUTPUT
	END TRY
	BEGIN CATCH
		SET @json_output = null
	END CATCH
END

